// App.jsx
import React, { useState } from 'react';
import SearchBar from './components/SearchBar';
import CityCard from './components/CityCard';
import ForecastChart from './components/ForecastChart';
import { fetchCityWeather } from './weatherApi';

export default function App() {
  const [cities, setCities] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleAddCity = async (name) => {
    if (cities.length >= 5) {
      setError('Maximum 5 cities allowed.');
      return;
    }
    if (cities.find((c) => c.name.toLowerCase() === name.toLowerCase())) {
      setError(`"${name}" is already added.`);
      return;
    }

    setLoading(true);
    setError('');

    try {
      const data = await fetchCityWeather(name);
      setCities((prev) => [...prev, data]);
    } catch (e) {
      setError(e.message || 'Failed to fetch weather data.');
    } finally {
      setLoading(false);
    }
  };

  const handleRemove = (index) => {
    setCities((prev) => prev.filter((_, i) => i !== index));
  };

  const handleClearAll = () => {
    setCities([]);
    setError('');
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        {/* Header */}
        <header style={styles.header}>
          <h1 style={styles.title}>🌤 Weather Comparison</h1>
          <p style={styles.subtitle}>
            Compare 5-day forecasts for up to 5 cities side by side
          </p>
        </header>

        {/* Search bar */}
        <SearchBar
          onAdd={handleAddCity}
          disabled={loading || cities.length >= 5}
          cityCount={cities.length}
        />

        {/* City pills */}
        {cities.length > 0 && (
          <div style={styles.pillsRow}>
            {cities.map((c, i) => (
              <span key={i} style={styles.pill}>
                {c.current?.icon} {c.name}, {c.country}
                <button
                  style={styles.pillRemove}
                  onClick={() => handleRemove(i)}
                  aria-label={`Remove ${c.name}`}
                >
                  ×
                </button>
              </span>
            ))}
            <button style={styles.clearBtn} onClick={handleClearAll}>
              Clear all
            </button>
          </div>
        )}

        {/* Error */}
        {error && (
          <div style={styles.errorBox} role="alert">
            ⚠️ {error}
          </div>
        )}

        {/* Loading indicator */}
        {loading && (
          <div style={styles.loadingBox}>
            <span style={styles.spinner}>⏳</span> Fetching forecast data...
          </div>
        )}

        {/* Empty state */}
        {!loading && cities.length === 0 && !error && (
          <div style={styles.emptyState}>
            <div style={styles.emptyIcon}>🌍</div>
            <p style={styles.emptyText}>No cities added yet</p>
            <p style={styles.emptyHint}>
              Try adding: London, Tokyo, New York, Mumbai, Sydney
            </p>
          </div>
        )}

        {/* City cards grid */}
        {cities.length > 0 && (
          <div style={styles.grid}>
            {cities.map((city, i) => (
              <CityCard
                key={i}
                city={city}
                index={i}
                onRemove={() => handleRemove(i)}
              />
            ))}
          </div>
        )}

        {/* Forecast chart */}
        {cities.length > 0 && <ForecastChart cities={cities} />}
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #f0f4ff 0%, #e8f4fd 100%)',
    padding: '2rem 1rem',
  },
  container: {
    maxWidth: 1100,
    margin: '0 auto',
  },
  header: {
    marginBottom: '2rem',
  },
  title: {
    fontSize: 28,
    fontWeight: 700,
    color: '#1a1a2e',
    marginBottom: 6,
  },
  subtitle: {
    fontSize: 15,
    color: '#666',
  },
  pillsRow: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: 8,
    marginBottom: 20,
    alignItems: 'center',
  },
  pill: {
    display: 'flex',
    alignItems: 'center',
    gap: 6,
    background: '#fff',
    border: '1px solid #dde3ee',
    borderRadius: 20,
    padding: '4px 12px',
    fontSize: 13,
    color: '#444',
  },
  pillRemove: {
    background: 'none',
    border: 'none',
    fontSize: 16,
    color: '#aaa',
    cursor: 'pointer',
    padding: 0,
    lineHeight: 1,
  },
  clearBtn: {
    background: 'none',
    border: '1px solid #dde3ee',
    borderRadius: 20,
    padding: '4px 14px',
    fontSize: 13,
    color: '#888',
    cursor: 'pointer',
  },
  errorBox: {
    background: '#fff2f2',
    border: '1px solid #ffcdd2',
    borderRadius: 10,
    padding: '10px 16px',
    fontSize: 14,
    color: '#c0392b',
    marginBottom: 20,
  },
  loadingBox: {
    textAlign: 'center',
    padding: '2rem',
    color: '#666',
    fontSize: 15,
  },
  spinner: { fontSize: 20 },
  emptyState: {
    textAlign: 'center',
    padding: '4rem 2rem',
    color: '#888',
  },
  emptyIcon: { fontSize: 52, marginBottom: 12 },
  emptyText: { fontSize: 16, fontWeight: 600, marginBottom: 6 },
  emptyHint: { fontSize: 14 },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))',
    gap: 16,
    marginBottom: 8,
  },
};
